namespace ui {
namespace {

#ifndef TERM4K_VERSION
#define TERM4K_VERSION "dev"
#endif

std::string nowDateTimeString() {
    const auto now = std::chrono::system_clock::now();
    const std::time_t t = std::chrono::system_clock::to_time_t(now);
    std::tm local{};
#if defined(_WIN32)
    localtime_s(&local, &t);
#else
    local = *std::localtime(&t);
#endif
    std::ostringstream out;
    out << std::put_time(&local, "%Y-%m-%d %H:%M:%S");
    return out.str();
}

} // namespace

int HomePageUI::run() {
    using namespace ftxui;

    I18nService::instance().ensureLocaleLoaded(RuntimeConfigs::locale);
    auto tr = [](const std::string &key) {
        return I18nService::instance().get(key);
    };

    ThemePalette palette = ThemeAdapter::resolveFromRuntime();
    auto screen = ScreenInteractive::Fullscreen();
    std::atomic<bool> ticking{true};
    int nextAction = 0;

    const std::array<std::string, 6> logo = {
        "████████╗███████╗██████╗ ███╗   ███╗██╗   ██╗██╗  ██╗",
        "╚══██╔══╝██╔════╝██╔══██╗████╗ ████║██║   ██║██║ ██╔╝",
        "   ██║   █████╗  ██████╔╝██╔████╔██║████████║█████╔╝ ",
        "   ██║   ██╔══╝  ██╔══██╗██║╚██╔╝██║╚═════██║██╔═██╗ ",
        "   ██║   ███████╗██║  ██║██║ ╚═╝ ██║      ██║██║  ██╗",
        "   ╚═╝   ╚══════╝╚═╝  ╚═╝╚═╝     ╚═╝      ╚═╝╚═╝  ╚═╝",
    };

    std::vector<std::string> entries = {
        tr("ui.home.menu.start_game"),
        tr("ui.home.menu.settings"),
        tr("ui.home.menu.player_info"),
        tr("ui.home.menu.quit"),
    };
    const std::array<std::string, 4> icons = {"", "", "", ""};
    int selected = 0;

    auto root = Renderer([&] {
        Elements logoLines;
        for (const std::string &line : logo) {
            logoLines.push_back(text(line) | bold | color(toColor(palette.accentPrimary)) | center);
        }

        Elements menuRows;
        for (std::size_t i = 0; i < entries.size(); ++i) {
            Element line = hbox({
                text(icons[i]),
                text("  "),
                text(entries[i]),
            });
            if (static_cast<int>(i) == selected) {
                line = line |
                       bold |
                       color(highContrastOn(palette.accentPrimary)) |
                       bgcolor(toColor(palette.accentPrimary));
            } else {
                line = line | color(toColor(palette.textPrimary));
            }

            menuRows.push_back(hbox({filler(), line, filler()}));
            if (i + 1 < entries.size()) {
                // Two-line gap between options.
                menuRows.push_back(text(""));
                menuRows.push_back(text(""));
            }
        }

        Element menuArea = vbox(std::move(menuRows)) |
                           color(toColor(palette.textPrimary));

        Element menuPanel = hbox({text("   "), menuArea, text("   ")}) |
                            borderRounded |
                            color(toColor(palette.borderNormal));

        Element leftFooter = vbox({
                               text(std::string(TERM4K_VERSION)),
                               text(nowDateTimeString()),
                           }) |
                           color(toColor(palette.textMuted));

        Element rightFooter = vbox({
                                text("term4k") | bold | color(toColor(palette.accentPrimary)) | align_right,
                                text("github.com/TheBadRoger/term4k") | color(toColor(palette.textMuted)) | align_right,
                            });

        return vbox({
                   // Move logo closer to 1/4 of the screen height.
                   filler() | flex,
                   vbox(std::move(logoLines)),
                   text(""),
                   text(""),
                   text(""),
                   text(""),
                   hbox({filler(), menuPanel, filler()}),
                   filler() | flex,
                   hbox({leftFooter, filler(), rightFooter}),
               }) |
               bgcolor(toColor(palette.surfaceBg)) |
               color(toColor(palette.textPrimary)) |
               flex;
    });

    auto app = CatchEvent(root, [&](const Event &event) {
        if (event == Event::Character('q') || event == Event::Escape) {
            ticking = false;
            screen.ExitLoopClosure()();
            return true;
        }

        if (event == Event::ArrowUp || event == Event::Character('k')) {
            selected = (selected + static_cast<int>(entries.size()) - 1) % static_cast<int>(entries.size());
            return true;
        }

        if (event == Event::ArrowDown || event == Event::Character('j')) {
            selected = (selected + 1) % static_cast<int>(entries.size());
            return true;
        }

        if (event == Event::Return) {
            if (selected == 0) {
                nextAction = 1;
                ticking = false;
                screen.ExitLoopClosure()();
                return true;
            }

            if (selected == 1) {
                nextAction = 2;
                ticking = false;
                screen.ExitLoopClosure()();
                return true;
            }

            if (selected == 2) {
                nextAction = 5;
                ticking = false;
                screen.ExitLoopClosure()();
                return true;
            }

            if (selected == 3) {
                ticking = false;
                screen.ExitLoopClosure()();
                return true;
            }
            return true;
        }

        return false;
    });

    std::thread ticker([&] {
        while (ticking) {
            std::this_thread::sleep_for(std::chrono::seconds(1));
            if (!ticking) break;
            screen.PostEvent(Event::Custom);
        }
    });

    screen.Loop(app);
    ticking = false;
    if (ticker.joinable()) ticker.join();
    return nextAction;
}

} // namespace ui

#include "ui/LoginUI.h"

#include "config/RuntimeConfigs.h"
#include "instances/UserLoginInstance.h"
#include "services/I18nService.h"
#include "ui/ThemeAdapter.h"

#include <ftxui/component/component.hpp>
#include <ftxui/component/screen_interactive.hpp>
#include <ftxui/dom/elements.hpp>

#include <string>

namespace ui {
namespace {

ftxui::Color toColor(const Rgb &rgb) { return ftxui::Color::RGB(rgb.r, rgb.g, rgb.b); }

ftxui::Color highContrastOn(const Rgb &bg) {
    const int luma = (bg.r * 299 + bg.g * 587 + bg.b * 114) / 1000;
    return luma >= 140 ? ftxui::Color::Black : ftxui::Color::White;
}

} // namespace

int LoginUI::run() {
    using namespace ftxui;

    I18nService::instance().ensureLocaleLoaded(RuntimeConfigs::locale);
    auto tr = [](const std::string &key) { return I18nService::instance().get(key); };
    const ThemePalette palette = ThemeAdapter::resolveFromRuntime();

    std::string username;
    std::string password;
    std::string status = tr("ui.auth.status.idle");

    InputOption userOpt;
    userOpt.placeholder = tr("ui.login.username");
    auto usernameInput = Input(&username, userOpt);

    InputOption passOpt;
    passOpt.password = true;
    passOpt.placeholder = tr("ui.login.password");
    auto passwordInput = Input(&password, passOpt);

    auto container = Container::Vertical({usernameInput, passwordInput});
    int focusIndex = 0;

    auto screen = ScreenInteractive::Fullscreen();
    auto root = Renderer(container, [&] {
        Element user = window(text(" " + tr("ui.login.username") + " "), usernameInput->Render()) |
                       color(toColor(focusIndex == 0 ? palette.accentPrimary : palette.borderNormal)) |
                       bgcolor(toColor(palette.surfacePanel));
        Element pass = window(text(" " + tr("ui.login.password") + " "), passwordInput->Render()) |
                       color(toColor(focusIndex == 1 ? palette.accentPrimary : palette.borderNormal)) |
                       bgcolor(toColor(palette.surfacePanel));

        Element hint = text(tr("ui.login.hint")) | color(toColor(palette.textMuted));
        Element statusLine = text(status) | color(toColor(palette.textMuted));

        Element submit = text(" " + tr("ui.auth.action.login") + " ") |
                         bold |
                         color(highContrastOn(palette.accentPrimary)) |
                         bgcolor(toColor(palette.accentPrimary));

        return vbox({
                   text(tr("ui.auth.login_title")) | bold | color(toColor(palette.accentPrimary)),
                   separator(),
                   user,
                   pass,
                   text(""),
                   hbox({submit, text("  "), hint}),
                   separator(),
                   statusLine,
               }) |
               borderRounded |
               bgcolor(toColor(palette.surfaceBg)) |
               color(toColor(palette.textPrimary)) |
               center;
    });

    UserLoginInstance loginInstance;
    auto app = CatchEvent(root, [&](const Event &event) {
        if (event == Event::Escape || event == Event::Character('q')) {
            screen.ExitLoopClosure()();
            return true;
        }
        if (event == Event::Tab) {
            focusIndex = (focusIndex + 1) % 2;
            return true;
        }
        if (event == Event::ArrowUp || event == Event::Character('k')) {
            focusIndex = (focusIndex + 1) % 2;
            return true;
        }
        if (event == Event::ArrowDown || event == Event::Character('j')) {
            focusIndex = (focusIndex + 1) % 2;
            return true;
        }
        if (event == Event::Return) {
            if (loginInstance.login(username, password)) {
                status = tr("ui.login.result.login_succeeded");
            } else {
                status = tr("ui.login.result.login_failed");
            }
            return true;
        }
        if (focusIndex == 0) return usernameInput->OnEvent(event);
        return passwordInput->OnEvent(event);
    });

    screen.Loop(app);
    return 0;
}

} // namespace ui

